#!/bin/bash set -e # ============================ # CONFIGURATION # ============================ REGION="us-west-2" AZ="${REGION}a" # Blueprints MASTER_BLUEPRINT="ubuntu_22_04" WORKER1_BLUEPRINT="amazon_linux_2023" WORKER2_BLUEPRINT="ubuntu_22_04" BUNDLE="nano_2_0" KEY_NAME="gui-key" KEY_FILE="gui-key.pem" MASTER="ansible-master" WORKER1="worker-node-1" WORKER2="worker-node-2" # ============================ # CREATE SSH KEY IF NOT EXISTS # ============================ if ! aws lightsail get-key-pair --key-pair-name "$KEY_NAME" &>/dev/null; then     echo "🔑 Creating Lightsail key pair..."     aws lightsail create-key-pair \         --key-pair-name "$KEY_NAME" \         --query 'privateKeyBase64' \         --output text > "$KEY_FILE"     chmod 400 "$KEY_FILE" else     echo "⚠️ Key $KEY_NAME already exists, using existing key." fi # ============================ # CREATE INSTANCES # ============================ declare -A BLUEPRINTS BLUEPRINTS[$MASTER]=$MASTER_BLUEPRINT BLUEPRINTS[$WORKER1]=$WORKER1_BLUEPRINT BLUEPRINTS[$WORKER2]=$WORKER2_BLUEPRINT for NODE in $MASTER $WORKER1 $WORKER2; do     if aws lightsail get-instance --instance-name "$NODE" &>/dev/null; then         echo "⚠️ Instance $NODE already exists, skipping creation."     else         echo "🚀 Creating instance $NODE..."         aws lightsail create-instances \             --region "$REGION" \             --instance-names "$NODE" \             --availability-zone "$AZ" \             --blueprint-id "${BLUEPRINTS[$NODE]}" \             --bundle-id "$BUNDLE" \             --key-pair-name "$KEY_NAME"     fi done # ============================ # FETCH PUBLIC IPS # ============================ echo "⏳ Waiting 60s for instances to initialize..." sleep 60 MASTER_PUBLIC_IP=$(aws lightsail get-instance \     --instance-name "$MASTER" \     --query 'instance.publicIpAddress' \     --output text) WORKER1_PUBLIC_IP=$(aws lightsail get-instance \     --instance-name "$WORKER1" \     --query 'instance.publicIpAddress' \     --output text) WORKER2_PUBLIC_IP=$(aws lightsail get-instance \     --instance-name "$WORKER2" \     --query 'instance.publicIpAddress' \     --output text) echo "Master Public IP : $MASTER_PUBLIC_IP" echo "Worker1 Public   : $WORKER1_PUBLIC_IP" echo "Worker2 Public   : $WORKER2_PUBLIC_IP" # ============================ # WAIT FOR SSH ON MASTER # ============================ echo "⏳ Waiting for SSH on master..." until ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ubuntu@$MASTER_PUBLIC_IP "echo SSH ready" &>/dev/null; do     sleep 10 done # ============================ # INSTALL ANSIBLE ON MASTER # ============================ ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ubuntu@$MASTER_PUBLIC_IP << 'EOF' export DEBIAN_FRONTEND=noninteractive # Update & install Ansible sudo apt update -y sudo apt upgrade -y sudo apt install -y ansible # Generate SSH key for Ansible (master -> workers) ssh-keygen -t rsa -b 2048 -f ~/.ssh/id_rsa -N "" EOF # ============================ # COPY MASTER PUBLIC KEY TO WORKERS # ============================ echo "🔑 Copying master SSH key to workers..." MASTER_PUB_KEY=$(ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ubuntu@$MASTER_PUBLIC_IP "cat ~/.ssh/id_rsa.pub") # Worker1 (Amazon Linux, ec2-user) ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ec2-user@$WORKER1_PUBLIC_IP \     "mkdir -p ~/.ssh && echo '$MASTER_PUB_KEY' >> ~/.ssh/authorized_keys && chmod 700 ~/.ssh && chmod 600 ~/.ssh/authorized_keys" # Worker2 (Ubuntu) ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ubuntu@$WORKER2_PUBLIC_IP \     "mkdir -p ~/.ssh && echo '$MASTER_PUB_KEY' >> ~/.ssh/authorized_keys && chmod 700 ~/.ssh && chmod 600 ~/.ssh/authorized_keys" # ============================ # CREATE ANSIBLE WORKSPACE AND INVENTORY # ============================ ssh -o StrictHostKeyChecking=no -i "$KEY_FILE" ubuntu@$MASTER_PUBLIC_IP << EOF mkdir -p ~/ansible-dev cd ~/ansible-dev # Inventory with group-specific SSH users cat <<EOT > inventory.ini [webservers] $WORKER1_PUBLIC_IP [databaseservers] $WORKER2_PUBLIC_IP [webservers:vars] ansible_ssh_private_key_file=~/.ssh/id_rsa ansible_user=ec2-user [databaseservers:vars] ansible_ssh_private_key_file=~/.ssh/id_rsa ansible_user=ubuntu EOT # Ansible config cat <<EOT > ansible.cfg [defaults] inventory = inventory.ini host_key_checking = False interpreter_python = auto_silent deprecation_warnings = False localhost_warning = False EOT # Test Ansible connectivity ansible all -m ping EOF echo "🎉 Fully automated Ansible lab setup COMPLETE!"

